import requests
from bs4 import BeautifulSoup
import json

def enviar_consulta_especifica():
    url = "https://chess-results.com/turniersuche.aspx?lan=2"
    
    # Cabeceras necesarias para que el servidor no rechace la petición
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
        'Content-Type': 'application/x-www-form-urlencoded',
        'Origin': 'https://chess-results.com',
        'Referer': url
    }

    session = requests.Session()

    try:
        # 1. Obtener la página inicial para asegurar que tenemos una cookie de sesión válida
        print("Estableciendo conexión...")
        session.get(url, headers=headers)

        # 2. Definir los datos exactos que proporcionaste
        # Nota: He mantenido los valores de VIEWSTATE y VALIDATION que me pasaste
        payload = {
            '__EVENTTARGET': '',
            '__EVENTARGUMENT': '',
            '__LASTFOCUS': '',
            '__VIEWSTATE': '',
            '__VIEWSTATEGENERATOR': '11983972',
            '__EVENTVALIDATION': '',
            'ctl00$P1$txt_leiter': '',
            'ctl00$P1$cb_suchen': 'Buscar',
            'ctl00$P1$combo_art': '5',
            'ctl00$P1$combo_sort': '1',
            'ctl00$P1$combo_land': 'ESP',
            'ctl00$P1$combo_bedenkzeit': '0',
            'ctl00$P1$combo_anzahl_zeilen': '5',
            'ctl00$P1$txt_tnr': '',
            'ctl00$P1$txt_bez': '',
            'ctl00$P1$txt_veranstalter': '',
            'ctl00$P1$txt_Hauptschiedsrichter': '',
            'ctl00$P1$txt_Schiedsrichter': '',
            'ctl00$P1$txt_ort': '',
            'ctl00$P1$txt_von_tag': '2026-03-19',
            'ctl00$P1$txt_bis_tag': '2027-08-31',
            'ctl00$P1$txt_eventid': ''
        }

        print("Enviando POST de búsqueda...")
        # El servidor procesa el envío
        response = session.post(url, data=payload, headers=headers)
        print(response.text)
        # 3. Analizar la respuesta
        soup = BeautifulSoup(response.text, 'html.parser')
        table = soup.find('table', {'class': 'CRtable'})

        if not table:
            print("No se encontró la tabla de resultados. Es posible que los tokens hayan expirado.")
            return

        print("\nResultados encontrados:")
        torneos = []
        filas = table.find_all('tr')[1:] # Saltar cabecera
        for fila in filas:
            cols = fila.find_all('td')
            if len(cols) >= 4:
                nombre = cols[1].text.strip()
                print(f"✅ {nombre}")
                torneos.append({"nombre": nombre})

        print(f"\nSe han extraído {len(torneos)} torneos.")

    except Exception as e:
        print(f"Ocurrió un error: {e}")

if __name__ == "__main__":
    enviar_consulta_especifica()